export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveCells = new Set(cells.map(([x, y]) => cellKey(x, y)));

  const countLiveNeighbors = (x: number, y: number): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => aliveCells.has(cellKey(x + dx, y + dy))).length;

  const candidates = new Map<string, Cell>();
  for (const [x, y] of cells) {
    candidates.set(cellKey(x, y), [x, y]);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      candidates.set(cellKey(nx, ny), [nx, ny]);
    }
  }

  const result: Cell[] = [];
  for (const [x, y] of candidates.values()) {
    const n = countLiveNeighbors(x, y);
    const isAlive = aliveCells.has(cellKey(x, y));
    if (isAlive && SURVIVAL_NEIGHBOR_COUNTS.includes(n)) {
      result.push([x, y]);
    } else if (!isAlive && n === 3) {
      result.push([x, y]);
    }
  }
  return result;
}

